CodeInjections.CodeInjection:
float  circleRadius;
float  lineWidth;
float4 lineColor;
float  emissionIntensity;
float  dashLength;
float  dashGap;
float  animSpeed;

float  gMask;
float3 gColor;
float  gTerrainHeightMask;

float3 worldPos = getWorldPosition(In);

globals.gTerrainHeightMask = getHeightAboveTerrain(worldPos, 0);

float2 uv = In.vs.defaultTexCoords;

float2 p = (In.vs.defaultTexCoords - 0.5) * 2;
float  r = length(p);

float inner = object.circleRadius - object.lineWidth * 0.5;
float outer = object.circleRadius + object.lineWidth * 0.5;

globals.gMask = step(inner, r) * (1.0 - step(outer, r));

if (globals.gMask > 0.0)
{
    float angle = atan2(p.y, p.x);
    float arc   = angle * object.circleRadius;

    arc += cTime_s * object.animSpeed;

    float cycle = object.dashLength + object.dashGap;
    float m     = fmod(arc, cycle);

    if (m < 0.0)
        m += cycle;

    if (m > object.dashLength)
        globals.gMask = 0.0;
}

globals.gColor = object.lineColor.rgb;

if (globals.gTerrainHeightMask < 0.0) {
    diffuseColor.rgb = float3(1.0, 1.0, 1.0);
} else {
    diffuseColor.rgb = float3(1.0, 0.3, 0.0);
}
